export function normalizeDivisionName(name) {
  const n = String(name || '').trim();
  if (!n) return '';
  const lower = n.toLowerCase();
  if (lower === 'chattogram') return 'Chittagong';
  if (lower === 'barishal') return 'Barisal';
  if (lower === 'rajshani') return 'Rajshahi';
  const match = BD_DIVISION_PATHS.find(
    (d) => d.key.toLowerCase() === lower
      || d.label.toLowerCase() === lower
      || (d.aliases || []).some((a) => a.toLowerCase() === lower)
  );
  return match ? match.key : n;
}

/**
 * Harm / disease intensity — muted institutional reds
 * (warm paper → dust rose → brick → burgundy → oxblood)
 */
export function choroplethFill(totalCases, maxCases) {
  if (!totalCases || totalCases <= 0) return '#f7f1f0';
  const t = Math.min(1, totalCases / Math.max(maxCases, 1));
  if (t < 0.2) return '#e8d0cc';
  if (t < 0.4) return '#c9968f';
  if (t < 0.6) return '#a85f57';
  if (t < 0.8) return '#7e3a35';
  return '#4c1f1c';
}

/** High-contrast label color on muted red fills */
export function choroplethLabelColor(totalCases, maxCases) {
  if (!totalCases || totalCases <= 0) return '#5c2a26';
  const t = Math.min(1, totalCases / Math.max(maxCases, 1));
  return t < 0.45 ? '#3d1a17' : '#faf7f6';
}
